	this.frame_11 = function() {
		this.stop();
		var root = this; // Simpan referensi 'this' agar bisa diakses di dalam fungsi
		
		// 1. HITUNG DATA AKHIR
		var totalSoal = window.soalAcak ? window.soalAcak.length : 0;
		var jumlahBenar = window.skorBenar || 0;
		var jumlahSalah = totalSoal - jumlahBenar;
		
		// Rumus Nilai: (Benar / Total) * 100
		var skorAkhir = (totalSoal > 0) ? Math.round((jumlahBenar / totalSoal) * 100) : 0;
		
		// 2. TAMPILKAN KE TEXT FIELD
		if (root.txt_benar) root.txt_benar.text = String(jumlahBenar);
		if (root.txt_salah) root.txt_salah.text = String(jumlahSalah);
		if (root.txt_nilai) root.txt_nilai.text = String(skorAkhir);
		
		// 3. TOMBOL RESTART
		if (root.btn_ulang) {
		    root.btn_ulang.cursor = "pointer";
		    root.btn_ulang.removeAllEventListeners(); // Membersihkan listener lama agar tidak double
		    
		    root.btn_ulang.on("click", function() {
		        // Reset semua data global agar bersih saat mengulang
		        window.indeks = 0;
		        window.skorBenar = 0;
		        window.jawabanUser = "";
		        
		        // PENTING: Arahkan ke frame tempat tombol 'btn_mulai' berada.
		        // Jika btn_mulai ada di frame 1, gunakan 0. 
		        // Jika ada di frame 2, gunakan 1, dst.
		        root.gotoAndStop(0); 
		    });
		}
	}

